import json

with open("/tmp/investvault/chatgpt/conversations-001.json", "r") as f:
    data = json.load(f)

# Conversation 2 - find all nodes with actual content
convo = data[2]
mapping = convo.get('mapping', {})

found_reliance = []
for node_id, node in mapping.items():
    msg = node.get('message')
    if not msg:
        continue

    # Convert entire node to string to search
    node_str = json.dumps(node)
    if any(t in node_str for t in ['Reliance', 'Ambani', 'India']):
        role = msg.get('author', {}).get('role', 'N/A')
        content_type = msg.get('content', {}).get('content_type', 'N/A')
        parts = msg.get('content', {}).get('parts', [])

        text_parts = []
        for p in parts:
            if isinstance(p, str) and len(p) > 0:
                text_parts.append(p)
            elif isinstance(p, dict):
                # Check for nested text
                for k, v in p.items():
                    if isinstance(v, str) and any(t in v for t in ['Reliance', 'Ambani', 'India']):
                        text_parts.append(f"[{k}]: {v}")

        if text_parts:
            found_reliance.append((role, content_type, '\n'.join(text_parts)))
        else:
            # Check other fields
            for field in ['metadata', 'status']:
                field_str = json.dumps(msg.get(field, {}))
                if any(t in field_str for t in ['Reliance', 'Ambani']):
                    found_reliance.append((role, content_type, f"[in {field}]: {field_str[:1000]}"))

for role, ctype, text in found_reliance:
    print(f"\n{'='*60}")
    print(f"Role: {role}, Content type: {ctype}")
    print(text[:5000])

